#!/usr/bin/env node

/**
 * Comprehensive test for error handling and recovery systems
 * Tests error categorization, recovery strategies, and user feedback
 */

import { fileURLToPath } from 'url'
import { dirname, join } from 'path'

const __filename = fileURLToPath(import.meta.url)
const __dirname = dirname(__filename)

// Mock DOM environment for testing
global.window = {
  location: { origin: 'http://localhost:3000' },
  localStorage: {
    data: {},
    getItem(key) { return this.data[key] || null },
    setItem(key, value) { this.data[key] = value },
    removeItem(key) { delete this.data[key] }
  },
  URL: {
    createObjectURL: () => 'blob:mock-url',
    revokeObjectURL: () => {}
  }
}

global.document = {
  createElement: () => ({
    getContext: () => ({
      clearRect: () => {},
      fillRect: () => {},
      drawImage: () => {},
      fillText: () => {}
    })
  })
}

global.Image = class {
  constructor() {
    setTimeout(() => {
      if (this.onload) this.onload()
    }, 10)
  }
}

global.Blob = class {
  constructor(data, options = {}) {
    this.size = data.reduce((sum, item) => sum + (item.length || 0), 0)
    this.type = options.type || ''
  }
}

global.File = class extends global.Blob {
  constructor(data, name, options = {}) {
    super(data, options)
    this.name = name
    this.lastModified = Date.now()
  }
}

global.FileReader = class {
  readAsDataURL(blob) {
    setTimeout(() => {
      this.result = 'data:image/jpeg;base64,'
      if (this.onload) this.onload()
    }, 10)
  }
}

// Import the modules to test
async function importModules() {
  try {
    const errorHandlerModule = await import('../src/utils/errorHandling.js')
    const recoveryServiceModule = await import('../src/utils/coverRecoveryService.js')
    
    return {
      errorHandler: errorHandlerModule.default,
      recoveryService: recoveryServiceModule.default
    }
  } catch (error) {
    console.error('Failed to import modules:', error)
    process.exit(1)
  }
}

async function testErrorCategorization(errorHandler) {
  console.log('🧪 Testing Error Categorization...\n')
  
  const testCases = [
    {
      name: 'Network Error',
      error: new Error('Failed to fetch'),
      expectedCategory: 'NetworkError'
    },
    {
      name: 'Rate Limit Error',
      error: { status: 429, message: 'Too many requests' },
      expectedCategory: 'RateLimitError'
    },
    {
      name: 'Image Processing Error',
      error: new Error('Failed to load image'),
      expectedCategory: 'ImageProcessingError'
    },
    {
      name: 'Storage Error',
      error: { name: 'QuotaExceededError', message: 'Storage quota exceeded' },
      expectedCategory: 'StorageError'
    },
    {
      name: 'Upload Error',
      error: { status: 500, message: 'Internal server error' },
      expectedCategory: 'UploadError'
    },
    {
      name: 'Validation Error',
      error: new Error('Unsupported format: image/bmp'),
      expectedCategory: 'ValidationError'
    }
  ]
  
  let passed = 0
  let failed = 0
  
  for (const testCase of testCases) {
    try {
      const errorInfo = errorHandler.categorizeError(testCase.error)
      
      if (errorInfo.category === testCase.expectedCategory) {
        console.log(`✅ ${testCase.name}: ${errorInfo.category}`)
        passed++
      } else {
        console.log(`❌ ${testCase.name}: Expected ${testCase.expectedCategory}, got ${errorInfo.category}`)
        failed++
      }
    } catch (error) {
      console.log(`❌ ${testCase.name}: Error during categorization - ${error.message}`)
      failed++
    }
  }
  
  console.log(`\n📊 Error Categorization Results: ${passed} passed, ${failed} failed\n`)
  return { passed, failed }
}

async function testRetryStrategies(errorHandler) {
  console.log('🔄 Testing Retry Strategies...\n')
  
  const testCases = [
    {
      name: 'Network Error Retry',
      error: new Error('Failed to fetch'),
      context: { attempt: 0 },
      shouldRetry: true
    },
    {
      name: 'Rate Limit Retry',
      error: { status: 429, message: 'Rate limited' },
      context: { attempt: 1 },
      shouldRetry: true
    },
    {
      name: 'Max Retries Exceeded',
      error: new Error('Failed to fetch'),
      context: { attempt: 5 },
      shouldRetry: false
    },
    {
      name: 'Validation Error No Retry',
      error: new Error('Invalid file format'),
      context: { attempt: 0 },
      shouldRetry: false
    }
  ]
  
  let passed = 0
  let failed = 0
  
  for (const testCase of testCases) {
    try {
      const result = await errorHandler.handleError(testCase.error, testCase.context)
      
      if (result.shouldRetry === testCase.shouldRetry) {
        console.log(`✅ ${testCase.name}: Retry decision correct (${result.shouldRetry})`)
        passed++
      } else {
        console.log(`❌ ${testCase.name}: Expected shouldRetry=${testCase.shouldRetry}, got ${result.shouldRetry}`)
        failed++
      }
    } catch (error) {
      console.log(`❌ ${testCase.name}: Error during retry strategy test - ${error.message}`)
      failed++
    }
  }
  
  console.log(`\n📊 Retry Strategy Results: ${passed} passed, ${failed} failed\n`)
  return { passed, failed }
}

async function testRecoveryStrategies(recoveryService) {
  console.log('🛠️ Testing Recovery Strategies...\n')
  
  const testCases = [
    {
      name: 'Network Failure Recovery',
      error: new Error('Failed to fetch'),
      context: { operation: 'upload', comicId: 'test-comic' },
      expectedStrategies: ['retry_with_backoff', 'switch_to_offline']
    },
    {
      name: 'Storage Failure Recovery',
      error: { name: 'QuotaExceededError' },
      context: { operation: 'storage', file: new global.File(['test'], 'test.jpg') },
      expectedStrategies: ['clear_cache_and_retry', 'switch_storage_strategy']
    },
    {
      name: 'API Failure Recovery',
      error: { status: 503, message: 'Service unavailable' },
      context: { operation: 'cover_search', provider: 'comicvine' },
      expectedStrategies: ['try_alternative_provider', 'retry_with_delay']
    }
  ]
  
  let passed = 0
  let failed = 0
  
  for (const testCase of testCases) {
    try {
      const result = await recoveryService.attemptRecovery(testCase.error, testCase.context)
      
      if (result.success || result.manualStrategies) {
        console.log(`✅ ${testCase.name}: Recovery strategies available`)
        
        if (result.manualStrategies) {
          const availableStrategies = result.manualStrategies.map(s => s.action)
          const hasExpectedStrategies = testCase.expectedStrategies.some(expected => 
            availableStrategies.includes(expected)
          )
          
          if (hasExpectedStrategies) {
            console.log(`   Available strategies: ${availableStrategies.join(', ')}`)
          } else {
            console.log(`   ⚠️ Expected strategies not found: ${testCase.expectedStrategies.join(', ')}`)
          }
        }
        
        passed++
      } else {
        console.log(`❌ ${testCase.name}: No recovery strategies available`)
        failed++
      }
    } catch (error) {
      console.log(`❌ ${testCase.name}: Error during recovery test - ${error.message}`)
      failed++
    }
  }
  
  console.log(`\n📊 Recovery Strategy Results: ${passed} passed, ${failed} failed\n`)
  return { passed, failed }
}

async function testUserFeedback(errorHandler) {
  console.log('💬 Testing User Feedback System...\n')
  
  let feedbackReceived = []
  
  // Register feedback callback
  const unsubscribe = errorHandler.onUserFeedback((notification) => {
    feedbackReceived.push(notification)
  })
  
  const testErrors = [
    new Error('Failed to fetch'),
    { status: 429, message: 'Rate limited' },
    new Error('Invalid image format')
  ]
  
  let passed = 0
  let failed = 0
  
  for (let i = 0; i < testErrors.length; i++) {
    try {
      await errorHandler.handleError(testErrors[i], { operation: 'test', attempt: 0 })
      
      // Check if feedback was generated
      if (feedbackReceived.length > i) {
        console.log(`✅ Feedback generated for error ${i + 1}: ${feedbackReceived[i].type}`)
        passed++
      } else {
        console.log(`❌ No feedback generated for error ${i + 1}`)
        failed++
      }
    } catch (error) {
      console.log(`❌ Error during feedback test ${i + 1}: ${error.message}`)
      failed++
    }
  }
  
  // Cleanup
  unsubscribe()
  
  console.log(`\n📊 User Feedback Results: ${passed} passed, ${failed} failed\n`)
  return { passed, failed }
}

async function testErrorRecoveryIntegration(errorHandler, recoveryService) {
  console.log('🔗 Testing Error Handler + Recovery Service Integration...\n')
  
  const testCases = [
    {
      name: 'Network Error with Automatic Recovery',
      error: new Error('Failed to fetch'),
      context: { operation: 'upload', comicId: 'test-comic', attempt: 0 }
    },
    {
      name: 'Storage Error with Recovery Options',
      error: { name: 'QuotaExceededError', message: 'Storage full' },
      context: { operation: 'storage', file: new global.File(['test'], 'test.jpg') }
    }
  ]
  
  let passed = 0
  let failed = 0
  
  for (const testCase of testCases) {
    try {
      // Handle error through error handler
      const errorResult = await errorHandler.handleError(testCase.error, testCase.context)
      
      // Attempt recovery through recovery service
      const recoveryResult = await recoveryService.attemptRecovery(testCase.error, testCase.context)
      
      if (errorResult && recoveryResult) {
        console.log(`✅ ${testCase.name}: Integration successful`)
        console.log(`   Error handled: ${!!errorResult.userMessage}`)
        console.log(`   Recovery available: ${recoveryResult.success || !!recoveryResult.manualStrategies}`)
        passed++
      } else {
        console.log(`❌ ${testCase.name}: Integration failed`)
        failed++
      }
    } catch (error) {
      console.log(`❌ ${testCase.name}: Integration error - ${error.message}`)
      failed++
    }
  }
  
  console.log(`\n📊 Integration Results: ${passed} passed, ${failed} failed\n`)
  return { passed, failed }
}

async function testErrorStatistics(errorHandler, recoveryService) {
  console.log('📈 Testing Error Statistics and Monitoring...\n')
  
  try {
    // Generate some test errors
    const testErrors = [
      new Error('Network error 1'),
      new Error('Network error 2'),
      { status: 429, message: 'Rate limit 1' },
      new Error('Processing error 1')
    ]
    
    for (const error of testErrors) {
      await errorHandler.handleError(error, { operation: 'test' })
    }
    
    // Get error statistics
    const errorStats = errorHandler.getErrorStats()
    const recoveryStats = recoveryService.getRecoveryStats()
    
    console.log('📊 Error Statistics:')
    console.log(`   Total errors: ${errorStats.total}`)
    console.log(`   By category: ${JSON.stringify(errorStats.byCategory, null, 2)}`)
    console.log(`   By severity: ${JSON.stringify(errorStats.bySeverity, null, 2)}`)
    
    console.log('\n🛠️ Recovery Statistics:')
    console.log(`   Total recoveries: ${recoveryStats.total}`)
    console.log(`   Successful: ${recoveryStats.successful}`)
    console.log(`   By failure type: ${JSON.stringify(recoveryStats.byFailureType, null, 2)}`)
    
    if (errorStats.total > 0) {
      console.log('✅ Statistics collection working')
      return { passed: 1, failed: 0 }
    } else {
      console.log('❌ No statistics collected')
      return { passed: 0, failed: 1 }
    }
  } catch (error) {
    console.log(`❌ Statistics test failed: ${error.message}`)
    return { passed: 0, failed: 1 }
  }
}

async function runAllTests() {
  console.log('🚀 Starting Comprehensive Error Handling Tests...\n')
  
  try {
    const { errorHandler, recoveryService } = await importModules()
    
    const results = {
      categorization: await testErrorCategorization(errorHandler),
      retryStrategies: await testRetryStrategies(errorHandler),
      recoveryStrategies: await testRecoveryStrategies(recoveryService),
      userFeedback: await testUserFeedback(errorHandler),
      integration: await testErrorRecoveryIntegration(errorHandler, recoveryService),
      statistics: await testErrorStatistics(errorHandler, recoveryService)
    }
    
    // Calculate totals
    const totalPassed = Object.values(results).reduce((sum, result) => sum + result.passed, 0)
    const totalFailed = Object.values(results).reduce((sum, result) => sum + result.failed, 0)
    const totalTests = totalPassed + totalFailed
    
    console.log('🎯 Final Test Results:')
    console.log('=' .repeat(50))
    
    Object.entries(results).forEach(([category, result]) => {
      const percentage = result.passed + result.failed > 0 
        ? Math.round((result.passed / (result.passed + result.failed)) * 100)
        : 0
      console.log(`${category.padEnd(20)}: ${result.passed}/${result.passed + result.failed} (${percentage}%)`)
    })
    
    console.log('=' .repeat(50))
    console.log(`Total: ${totalPassed}/${totalTests} tests passed (${Math.round((totalPassed / totalTests) * 100)}%)`)
    
    if (totalFailed === 0) {
      console.log('\n🎉 All error handling tests passed!')
      console.log('\n✅ Test Results:')
      console.log('   ✅ Error categorization: PASSED')
      console.log('   ✅ Retry strategies: PASSED')
      console.log('   ✅ Recovery strategies: PASSED')
      console.log('   ✅ User feedback system: PASSED')
      console.log('   ✅ Integration testing: PASSED')
      console.log('   ✅ Statistics and monitoring: PASSED')
    } else {
      console.log(`\n⚠️ ${totalFailed} tests failed. Review the output above for details.`)
      process.exit(1)
    }
    
  } catch (error) {
    console.error('❌ Test execution failed:', error)
    process.exit(1)
  }
}

// Run the tests
runAllTests().catch(console.error)